import React, { createContext, useContext, useState, useCallback } from 'react';

const Ctx = createContext(null);

export function WorkflowProvider({ children }) {
  const [currentStep, setCurrentStep] = useState(1);

  // Upload state
  // Phases within the Upload route: 'select' | 'ready' | 'metadata'
  const [uploadPhase, setUploadPhase] = useState('select');

  const [manuscriptFiles, setManuscriptFiles] = useState([]);
  const [primaryFileId, setPrimaryFileId] = useState(null);

  // Book data
  const [bookDetails, setBookDetails] = useState({});
  const [preferences, setPreferences] = useState({});

  // Design sub-stages
  // 'typography' | 'layout' | 'trim' | 'summary'
  const [design, setDesign] = useState({
    analyzed: false,
    stage: 'typography',
    typography: null,
    layout: null,
    trim: null,
    saving: false,
    saveProgress: 0,
    saved: false,
  });

  const addFile = useCallback((fileMeta) => {
    setManuscriptFiles((prev) => {
      const i = prev.findIndex((f) => f.id === fileMeta.id);
      if (i >= 0) {
        const copy = prev.slice();
        copy[i] = { ...copy[i], ...fileMeta };
        return copy;
      }
      const next = [...prev, fileMeta];
      if (!primaryFileId) {
        // first file becomes primary by default
        setPrimaryFileId(fileMeta.id);
      }
      return next;
    });
  }, [primaryFileId]);

  const updateFile = useCallback((id, patch) => {
    setManuscriptFiles((prev) => prev.map((f) => (f.id === id ? { ...f, ...patch } : f)));
  }, []);

  const removeFile = useCallback((id) => {
    setManuscriptFiles((prev) => prev.filter((f) => f.id !== id));
    setPrimaryFileId((cur) => (cur === id ? null : cur));
  }, []);

  const value = {
    // global step
    currentStep, setCurrentStep,

    // upload
    uploadPhase, setUploadPhase,
    manuscriptFiles, addFile, updateFile, removeFile,
    primaryFileId, setPrimaryFileId,

    // book
    bookDetails, setBookDetails,
    preferences, setPreferences,

    // design
    design, setDesign,
  };

  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}

export function useWorkflow() {
  const ctx = useContext(Ctx);
  if (!ctx) throw new Error('useWorkflow must be used within a WorkflowProvider');
  return ctx;
}
